// HasSummary applies the HasEdge predicate on the "summary" edge.
func HasSummary() predicate.SummaryEvent {
	return predicate.SummaryEvent(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, false, SummaryTable, SummaryColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasSummaryWith applies the HasEdge predicate on the "summary" edge with a given conditions (other predicates).
func HasSummaryWith(preds ...predicate.Summary) predicate.SummaryEvent {
	return predicate.SummaryEvent(func(s *sql.Selector) {
		step := newSummaryStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.SummaryEvent) predicate.SummaryEvent {
	return predicate.SummaryEvent(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.SummaryEvent) predicate.SummaryEvent {
	return predicate.SummaryEvent(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.SummaryEvent) predicate.SummaryEvent {
	return predicate.SummaryEvent(sql.NotPredicates(p))
}
